193→export async function GET(request: NextRequest) {
194→  try {
195→    const userId = await getAuthenticatedUserId();
196→    const searchParams = request.nextUrl.searchParams;
197→    const month = searchParams.get("month");
198→    const year = searchParams.get("year");
199→
200→    const currentDate = new Date();
201→    const targetMonth = month ? parseInt(month) : currentDate.getMonth() + 1;
202→    const targetYear = year ? parseInt(year) : currentDate.getFullYear();
203→
204→    const startDate = new Date(targetYear, targetMonth - 1, 1);
205→    const endDate = new Date(targetYear, targetMonth, 0);
206→    endDate.setHours(23, 59, 59, 999);
207→
208→    // Check if viewing a past month (for auto-recording savings history)
209→    const isCurrentMonth = targetMonth === currentDate.getMonth() + 1 && targetYear === currentDate.getFullYear();
210→    const isPastMonth = new Date(targetYear, targetMonth - 1, 1) < new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
211→
212→    // Calculate date ranges for consolidated query
213→    const sixMonthsAgo = new Date(targetYear, targetMonth - 6, 1);
214→    const futureDate = new Date(targetYear, targetMonth + 3, 0); // For installments (next 3 months)
215→    futureDate.setHours(23, 59, 59, 999);
216→
217→    // Previous month boundaries
218→    const prevMonthStart = new Date(targetYear, targetMonth - 2, 1);
219→    const prevMonthEnd = new Date(targetYear, targetMonth - 1, 0);
220→    prevMonthEnd.setHours(23, 59, 59, 999);
221→
222→    // Weekly boundaries for current month
223→    const today = new Date();
224→    const currentWeekStart = getMondayOfWeek(today);
225→    currentWeekStart.setHours(0, 0, 0, 0);
226→    const prevWeekStart = new Date(currentWeekStart);
227→    prevWeekStart.setDate(prevWeekStart.getDate() - 7);
228→    const prevWeekEnd = new Date(currentWeekStart);
229→    prevWeekEnd.setDate(prevWeekEnd.getDate() - 1);
230→    prevWeekEnd.setHours(23, 59, 59, 999);
231→
232→    // ===========================================
233→    // OPTIMIZED: Run all queries in parallel
234→    // ===========================================
235→    const [
236→      // Query 1: All transactions for 6 months (includes current, previous, and monthly data)
237→      allTransactions,
238→      // Query 2: Active budgets
239→      budgets,
240→      // Query 3: Fixed expenses (distinct by description)
241→      fixedExpenses,
242→      // Query 4: Future installment transactions (for upcoming installments)
243→      futureInstallments,
244→      // Query 5: Standalone installments for projection
245→      standaloneInstallments,
246→      // Query 6: Savings goal setting
247→      savingsGoalSetting,
248→      // Query 7: Bill payments for 6 months (for partial payment adjustments)
249→      billPayments,
250→    ] = await Promise.all([
251→      // Query 1: All transactions for 6 months with category and installment info
252→      prisma.transaction.findMany({
253→        where: {
254→          userId,
255→          date: {
256→            gte: sixMonthsAgo,
257→            lte: endDate,
258→          },
259→          deletedAt: null,
260→        },
261→        include: {
262→          category: true,
263→          installment: true,
264→          investmentTransaction: { select: { id: true } },
265→        },
266→      }),
267→
268→      // Query 2: Active budgets with category
269→      prisma.budget.findMany({
270→        where: { userId, isActive: true },
271→        include: { category: true },
272→      }),
273→
274→      // Query 3: Fixed expenses (distinct by description)
275→      prisma.transaction.findMany({
276→        where: {
277→          userId,
278→          isFixed: true,
279→          type: "EXPENSE",
280→          deletedAt: null,
281→        },
282→        include: {
283→          category: true,
284→        },
285→        distinct: ["description"],
286→      }),
287→
288→      // Query 4: Future grouped installments (next 3 months)
289→      prisma.transaction.findMany({
290→        where: {
291→          userId,
292→          isInstallment: true,
293→          installmentId: { not: null },
294→          date: {
295→            gt: endDate,
296→            lte: futureDate,
297→          },
298→          deletedAt: null,
299→        },
300→        include: {
301→          category: true,
302→          installment: true,
303→        },
304→        orderBy: {
305→          date: "asc",
306→        },
307→      }),
308→
309→      // Query 5: Standalone installments for projection
310→      prisma.transaction.findMany({
311→        where: {
312→          userId,
313→          isInstallment: true,
314→          installmentId: null,
315→          totalInstallments: { not: null },
316→          currentInstallment: { not: null },
317→          deletedAt: null,
318→        },
319→        include: {
320→          category: true,
321→        },
322→      }),
323→
324→      // Query 6: Savings goal setting
325→      prisma.settings.findUnique({
326→        where: { key_userId: { key: "savingsGoal", userId } },
327→      }),
328→
329→      // Query 7: Bill payments for 6 months (for partial payment adjustments)
330→      prisma.billPayment.findMany({
331→        where: {
332→          userId,
333→          billYear: {
334→            gte: sixMonthsAgo.getFullYear(),
335→            lte: targetYear,
336→          },
337→        },
338→      }),
339→    ]);
340→
341→    // ===========================================
342→    // DERIVE DATA FROM CONSOLIDATED QUERIES
343→    // ===========================================
344→
345→    // Filter transactions for current month
346→    const transactions = allTransactions.filter((t) => {
347→      const tDate = new Date(t.date);
348→      return tDate >= startDate && tDate <= endDate;
349→    });
350→
351→    // Filter transactions for previous month
352→    const prevTransactions = allTransactions.filter((t) => {
353→      const tDate = new Date(t.date);
354→      return tDate >= prevMonthStart && tDate <= prevMonthEnd;
355→    });
356→
357→    // Calculate previous month totals and category breakdown
358→    let prevIncome = 0;
359→    let prevExpenseRaw = 0;
360→    const prevCategoryTotals: Record<string, { total: number; name: string; color: string }> = {};
361→
362→    for (const t of prevTransactions) {
363→      // Skip investment-linked transactions (deposits/withdrawals)
364→      if (t.investmentTransaction) continue;
365→
366→      if (t.type === "INCOME") {
367→        prevIncome += Math.abs(t.amount);
368→      } else if (t.type === "EXPENSE") {
369→        prevExpenseRaw += Math.abs(t.amount);
370→        // Track category totals for previous month
371→        if (t.category && t.categoryId) {
372→          if (!prevCategoryTotals[t.categoryId]) {
373→            prevCategoryTotals[t.categoryId] = {
374→              total: 0,
375→              name: t.category.name,
376→              color: t.category.color,
377→            };
378→          }
379→          prevCategoryTotals[t.categoryId].total += Math.abs(t.amount);
380→        }
381→      }
382→      // TRANSFER is ignored in totals
383→    }
384→
385→    // Apply partial payment adjustment for previous month
386→    // This reduces expenses by the amount that was carried/financed instead of paid
387→    const prevMonthNumber = prevMonthStart.getMonth() + 1;
388→    const prevMonthYear = prevMonthStart.getFullYear();
389→    const prevPartialPaymentAdjustment = calculatePartialPaymentAdjustment(
390→      billPayments,
391→      prevMonthNumber,
392→      prevMonthYear
393→    );
394→    const prevExpense = Math.max(0, prevExpenseRaw - prevPartialPaymentAdjustment);
395→
396→    // Calculate current month summary
397→    let income = 0;
398→    let expenseRaw = 0;
399→    const categoryTotals: Record<string, { total: number; name: string; color: string }> = {};
400→
401→    for (const t of transactions) {
402→      // Skip investment-linked transactions (deposits/withdrawals)
403→      if (t.investmentTransaction) continue;
404→
405→      if (t.type === "INCOME") {
406→        income += Math.abs(t.amount);
407→      } else if (t.type === "EXPENSE") {
408→        expenseRaw += Math.abs(t.amount);
409→      }
410→      // TRANSFER is ignored in totals
411→
412→      if (t.category && t.type === "EXPENSE") {
413→        if (!categoryTotals[t.categoryId!]) {
414→          categoryTotals[t.categoryId!] = {
415→            total: 0,
416→            name: t.category.name,
417→            color: t.category.color,
418→          };
419→        }
420→        categoryTotals[t.categoryId!].total += Math.abs(t.amount);
421→      }
422→    }
423→
424→    // Apply partial payment adjustment for current month
425→    // When a bill was partially paid, we show only what was paid (amountPaid),
426→    // not what was consumed (totalBillAmount). The carried amount appears
427→    // in subsequent months via generated carryover/financing transactions.
428→    const partialPaymentAdjustment = calculatePartialPaymentAdjustment(
429→      billPayments,
430→      targetMonth,
431→      targetYear
432→    );
433→    const expense = Math.max(0, expenseRaw - partialPaymentAdjustment);
434→
435→    // Calculate comparison percentages
436→    const incomeChange = prevIncome > 0 ? ((income - prevIncome) / prevIncome) * 100 : 0;
437→    const expenseChange = prevExpense > 0 ? ((expense - prevExpense) / prevExpense) * 100 : 0;
438→    const prevBalance = prevIncome - prevExpense;
439→    const balance = income - expense;
440→    const balanceChange = prevBalance !== 0 ? ((balance - prevBalance) / Math.abs(prevBalance)) * 100 : 0;
441→
442→    // Get category breakdown with previous month comparison
443→    const categoryBreakdown = Object.entries(categoryTotals)
444→      .map(([categoryId, data]) => {
445→        const prevTotal = prevCategoryTotals[categoryId]?.total || null;
446→        const changePercentage = prevTotal && prevTotal > 0
447→          ? ((data.total - prevTotal) / prevTotal) * 100
448→          : null;
449→
450→        return {
451→          categoryId,
452→          categoryName: data.name,
453→          categoryColor: data.color,
454→          total: data.total,
455→          percentage: expense > 0 ? (data.total / expense) * 100 : 0,
456→          previousTotal: prevTotal,
457→          changePercentage,
458→        };
459→      })
460→      .sort((a, b) => b.total - a.total);
461→
462→    // ===========================================
463→    // DERIVE MONTHLY DATA FROM 6-MONTH QUERY
464→    // ===========================================
465→    const monthlyData = [];
466→    for (let i = 5; i >= 0; i--) {
467→      const monthStart = new Date(targetYear, targetMonth - 1 - i, 1);
468→      const monthEnd = new Date(targetYear, targetMonth - i, 0);
469→      monthEnd.setHours(23, 59, 59, 999);
470→
471→      // Filter from already-fetched transactions
472→      const monthTransactions = allTransactions.filter((t) => {
473→        const tDate = new Date(t.date);
474→        return tDate >= monthStart && tDate <= monthEnd;
475→      });
476→
477→      let monthIncome = 0;
478→      let monthExpenseRaw = 0;
479→
480→      for (const t of monthTransactions) {
481→        // Skip investment-linked transactions (deposits/withdrawals)
482→        if (t.investmentTransaction) continue;
483→
484→        if (t.type === "INCOME") {
485→          monthIncome += Math.abs(t.amount);
486→        } else if (t.type === "EXPENSE") {
487→          monthExpenseRaw += Math.abs(t.amount);
488→        }
489→        // TRANSFER is ignored in totals
490→      }
491→
492→      // Apply partial payment adjustment for this month
493→      const monthNumber = monthStart.getMonth() + 1;
494→      const monthYear = monthStart.getFullYear();
495→      const monthPartialPaymentAdjustment = calculatePartialPaymentAdjustment(
496→        billPayments,
497→        monthNumber,
498→        monthYear
499→      );
500→      const monthExpense = Math.max(0, monthExpenseRaw - monthPartialPaymentAdjustment);
501→
502→      monthlyData.push({
503→        month: monthStart.toLocaleDateString("pt-BR", { month: "short" }),
504→        year: monthStart.getFullYear(),
505→        income: monthIncome,
506→        expense: monthExpense,
507→      });
508→    }
509→
510→    // ===========================================
511→    // WEEKLY SUMMARY (derived from existing data when possible)
512→    // ===========================================
513→    let weeklySummary = null;
514→    if (isCurrentMonth) {
515→      // End of current week (Sunday)
516→      const currentWeekEnd = new Date(currentWeekStart);
517→      currentWeekEnd.setDate(currentWeekEnd.getDate() + 6);
518→      currentWeekEnd.setHours(23, 59, 59, 999);
519→
520→      // Current week transactions (filter from already-fetched data)
521→      const currentWeekTransactions = transactions.filter((t) => {
522→        const tDate = new Date(t.date);
523→        return tDate >= currentWeekStart && tDate <= currentWeekEnd && t.type === "EXPENSE" && !t.investmentTransaction;
524→      });
525→
526→      const currentWeekTotal = currentWeekTransactions.reduce((sum, t) => sum + Math.abs(t.amount), 0);
527→
528→      // Previous week transactions (filter from 6-month data if available)
529→      const prevWeekTransactions = allTransactions.filter((t) => {
530→        const tDate = new Date(t.date);
531→        return tDate >= prevWeekStart && tDate <= prevWeekEnd && t.type === "EXPENSE" && !t.investmentTransaction;
532→      });
533→
534→      const prevWeekTotal = prevWeekTransactions.reduce((sum, t) => sum + Math.abs(t.amount), 0);
535→
536→      const weekChangePercentage = prevWeekTotal > 0
537→        ? ((currentWeekTotal - prevWeekTotal) / prevWeekTotal) * 100
538→        : null;
539→
540→      weeklySummary = {
541→        currentWeek: {
542→          total: currentWeekTotal,
543→          count: currentWeekTransactions.length,
544→          startDate: currentWeekStart.toISOString(),
545→          endDate: currentWeekEnd.toISOString(),
546→        },
547→        previousWeek: {
548→          total: prevWeekTotal,
549→          count: prevWeekTransactions.length,
550→        },
551→        changePercentage: weekChangePercentage,
552→      };
553→    }
554→
555→    // Weekly Breakdown: gastos por semana do mês
556→    const nonInvestmentTransactions = transactions.filter((t) => !t.investmentTransaction);
557→    const weeklyBreakdown = calculateWeeklyBreakdown(nonInvestmentTransactions, startDate, endDate);
558→
559→    // ===========================================
560→    // SAVINGS GOAL
561→    // ===========================================
562→    const savingsGoal = savingsGoalSetting ? parseFloat(savingsGoalSetting.value) : null;
563→    const currentSavings = income - expense;
564→    const savingsPercentage = savingsGoal && savingsGoal > 0
565→      ? (currentSavings / savingsGoal) * 100
566→      : null;
567→
568→    // Feature 15: Auto-record savings history for past months
569→    if (isPastMonth && savingsGoal && savingsGoal > 0) {
570→      try {
571→        await prisma.savingsHistory.upsert({
572→          where: {
573→            month_year_userId: {
574→              month: targetMonth,
575→              year: targetYear,
576→              userId,
577→            },
578→          },
579→          update: {
580→            goal: savingsGoal,
581→            actual: currentSavings,
582→            isAchieved: currentSavings >= savingsGoal,
583→            percentage: (currentSavings / savingsGoal) * 100,
584→          },
585→          create: {
586→            userId,
587→            month: targetMonth,
588→            year: targetYear,
589→            goal: savingsGoal,
590→            actual: currentSavings,
591→            isAchieved: currentSavings >= savingsGoal,
592→            percentage: (currentSavings / savingsGoal) * 100,
593→          },
594→        });
595→      } catch (e) {
596→        // Silently ignore errors - this is a best-effort feature
597→        console.error("Error auto-recording savings history:", e);
598→      }
599→    }
600→
601→    // ===========================================
602→    // BUDGET ALERTS (using already-fetched budgets)
603→    // ===========================================
604→    const allBudgets = budgets
605→      .map((budget) => {
606→        const spent = categoryTotals[budget.categoryId]?.total || 0;
607→        const percentage = budget.amount > 0 ? (spent / budget.amount) * 100 : 0;
608→        return {
609→          categoryId: budget.categoryId,
610→          categoryName: budget.category.name,
611→          categoryColor: budget.category.color,
612→          budgetAmount: budget.amount,
613→          spent,
614→          percentage,
615→          isOver: spent > budget.amount,
616→        };
617→      })
618→      .sort((a, b) => b.percentage - a.percentage);
619→
620→    const budgetAlerts = allBudgets.filter((budget) => budget.percentage >= 80);
621→
622→    // ===========================================
623→    // UPCOMING INSTALLMENTS (project from standalone)
624→    // ===========================================
625→    const projectedInstallments: typeof futureInstallments = [];
626→    for (const t of standaloneInstallments) {
627→      if (!t.currentInstallment || !t.totalInstallments) continue;
628→
629→      const remainingInstallments = t.totalInstallments - t.currentInstallment;
630→      const transactionDate = new Date(t.date);
631→
632→      for (let i = 1; i <= remainingInstallments; i++) {
633→        const futureInstallmentDate = new Date(transactionDate);
634→        futureInstallmentDate.setMonth(transactionDate.getMonth() + i);
635→
636→        // Only include if within the date range (after current month, before futureDate)
637→        if (futureInstallmentDate > endDate && futureInstallmentDate <= futureDate) {
638→          projectedInstallments.push({
639→            ...t,
640→            id: `${t.id}-projected-${i}`,
641→            date: futureInstallmentDate,
642→            description: `${t.description} (${t.currentInstallment + i}/${t.totalInstallments})`,
643→            currentInstallment: t.currentInstallment + i,
644→            installment: null,
645→          });
646→        }
647→      }
648→    }
649→
