 10→
 11→const MONTH_LABELS = [
 12→  "jan",
 13→  "fev",
 14→  "mar",
 15→  "abr",
 16→  "mai",
 17→  "jun",
 18→  "jul",
 19→  "ago",
 20→  "set",
 21→  "out",
 22→  "nov",
 23→  "dez",
 24→];
