 26→export async function GET(request: NextRequest) {
 27→  try {
 28→    const userId = await getAuthenticatedUserId();
 29→    const searchParams = request.nextUrl.searchParams;
 30→    const monthsParam = searchParams.get("months");
 31→    const numMonths = monthsParam ? Math.min(Math.max(parseInt(monthsParam), 1), 12) : 6;
 32→
 33→    const now = new Date();
 34→    const startOfCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
 35→    const endDate = new Date(now.getFullYear(), now.getMonth() + numMonths, 0);
 36→
 37→    // Fetch future installment transactions (from grouped installments)
 38→    const futureInstallments = await prisma.transaction.findMany({
 39→      where: {
 40→        userId,
 41→        isInstallment: true,
 42→        installmentId: { not: null }, // Only grouped installments
 43→        date: {
 44→          gte: startOfCurrentMonth,
 45→          lte: endDate,
 46→        },
 47→      },
 48→      include: {
 49→        installment: true,
 50→      },
 51→      orderBy: { date: "asc" },
 52→    });
 53→
 54→    // Fetch standalone installments (manually marked, without group)
 55→    // These need to have their future installments projected
 56→    const standaloneInstallments = await prisma.transaction.findMany({
 57→      where: {
 58→        userId,
 59→        isInstallment: true,
 60→        installmentId: null,
 61→        totalInstallments: { not: null },
 62→        currentInstallment: { not: null },
 63→      },
 64→    });
 65→
 66→    // Project future installments from standalone transactions
 67→    interface ProjectedInstallment {
 68→      description: string;
 69→      amount: number;
 70→      date: Date;
 71→      currentInstallment: number;
 72→      totalInstallments: number;
 73→    }
 74→
 75→    const projectedStandaloneInstallments: ProjectedInstallment[] = [];
 76→    standaloneInstallments.forEach((t) => {
 77→      if (!t.currentInstallment || !t.totalInstallments) return;
 78→
 79→      const remainingInstallments = t.totalInstallments - t.currentInstallment;
 80→      const transactionDate = new Date(t.date);
 81→
 82→      for (let i = 1; i <= remainingInstallments; i++) {
 83→        const futureDate = new Date(transactionDate);
 84→        futureDate.setMonth(transactionDate.getMonth() + i);
 85→
 86→        // Only include if within projection range
 87→        if (futureDate >= startOfCurrentMonth && futureDate <= endDate) {
 88→          projectedStandaloneInstallments.push({
 89→            description: t.description,
 90→            amount: Math.abs(t.amount),
 91→            date: futureDate,
 92→            currentInstallment: t.currentInstallment + i,
 93→            totalInstallments: t.totalInstallments,
 94→          });
 95→        }
 96→      }
 97→    });
 98→
 99→    // Fetch active recurring expenses/incomes
100→    const activeRecurring = await prisma.recurringExpense.findMany({
101→      where: {
102→        userId,
103→        isActive: true,
104→      },
105→    });
106→
107→    // For each recurring, find the most recent transaction to get the latest amount
108→    // (in case user edited the value)
109→    const recurringWithLatestAmount = await Promise.all(
110→      activeRecurring.map(async (recurring) => {
111→        const latestTransaction = await prisma.transaction.findFirst({
112→          where: {
113→            userId,
114→            recurringExpenseId: recurring.id,
115→          },
116→          orderBy: { date: "desc" },
117→          select: { amount: true },
118→        });
119→
120→        return {
121→          ...recurring,
122→          // Use the latest transaction amount if exists, otherwise use defaultAmount
123→          effectiveAmount: latestTransaction?.amount ?? recurring.defaultAmount,
124→        };
125→      })
126→    );
127→
128→    // Fetch all actual transactions for current month (for real expenses calculation)
129→    const endOfCurrentMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);
130→    const currentMonthTransactions = await prisma.transaction.findMany({
131→      where: {
132→        userId,
133→        date: {
134→          gte: startOfCurrentMonth,
135→          lte: endOfCurrentMonth,
136→        },
137→        deletedAt: null,
138→        investmentTransaction: null,
139→      },
140→    });
141→
142→    // Calculate actual expenses and income for current month
143→    const actualExpenses = currentMonthTransactions
144→      .filter((t) => t.type === "EXPENSE")
145→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
146→
147→    const actualIncome = currentMonthTransactions
148→      .filter((t) => t.type === "INCOME")
149→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
150→
151→    // Find which recurring expenses have already been charged this month
152→    const chargedRecurringIds = new Set(
153→      currentMonthTransactions
154→        .filter((t) => t.recurringExpenseId !== null)
155→        .map((t) => t.recurringExpenseId)
156→    );
157→
158→    // Filter recurring to only include those NOT yet charged (for current month projection)
159→    const pendingRecurring = recurringWithLatestAmount.filter(
160→      (r) => !chargedRecurringIds.has(r.id)
161→    );
162→
163→    // Build monthly projections
164→    const months: MonthProjection[] = [];
165→    let totalInstallmentsSum = 0;
166→    let totalRecurringExpensesSum = 0;
167→    let totalRecurringIncomeSum = 0;
168→    let totalActualExpensesSum = 0;
169→    let totalActualIncomeSum = 0;
170→
171→    for (let i = 0; i < numMonths; i++) {
172→      const isCurrentMonth = i === 0;
173→      const projMonth = now.getMonth() + i;
174→      const projYear = now.getFullYear() + Math.floor(projMonth / 12);
175→      const normalizedMonth = (projMonth % 12) + 1;
176→
177→      const monthLabel = `${MONTH_LABELS[normalizedMonth - 1]}/${String(projYear).slice(-2)}`;
178→
179→      // Get grouped installments for this month
180→      const monthInstallments = futureInstallments.filter((t) => {
181→        const tDate = new Date(t.date);
182→        return tDate.getMonth() + 1 === normalizedMonth && tDate.getFullYear() === projYear;
183→      });
184→
185→      // Get projected standalone installments for this month
186→      const monthStandaloneInstallments = projectedStandaloneInstallments.filter((t) => {
187→        return t.date.getMonth() + 1 === normalizedMonth && t.date.getFullYear() === projYear;
188→      });
189→
190→      const installmentItems: ProjectionInstallmentItem[] = [
191→        // From grouped installments
192→        ...monthInstallments.map((t) => ({
193→          description: t.description,
194→          amount: Math.abs(t.amount),
195→          currentInstallment: t.currentInstallment || 1,
196→          totalInstallments: t.installment?.totalInstallments || 1,
197→        })),
198→        // From projected standalone installments
199→        ...monthStandaloneInstallments.map((t) => ({
200→          description: t.description,
201→          amount: t.amount,
202→          currentInstallment: t.currentInstallment,
203→          totalInstallments: t.totalInstallments,
204→        })),
205→      ];
206→
207→      const installmentsTotal =
208→        monthInstallments.reduce((sum, t) => sum + Math.abs(t.amount), 0) +
209→        monthStandaloneInstallments.reduce((sum, t) => sum + t.amount, 0);
210→      totalInstallmentsSum += installmentsTotal;
211→
212→      // For current month: use only pending recurring (not yet charged)
213→      // For future months: use all recurring
214→      const recurringToUse = isCurrentMonth ? pendingRecurring : recurringWithLatestAmount;
215→
216→      const recurringItems: ProjectionRecurringItem[] = recurringToUse.map((r) => ({
217→        description: r.description,
218→        amount: Math.abs(r.effectiveAmount),
219→        type: r.type as "INCOME" | "EXPENSE",
220→      }));
221→
222→      const recurringExpensesPending = recurringToUse
223→        .filter((r) => r.type === "EXPENSE")
224→        .reduce((sum, r) => sum + Math.abs(r.effectiveAmount), 0);
225→
226→      const recurringIncomePending = recurringToUse
227→        .filter((r) => r.type === "INCOME")
228→        .reduce((sum, r) => sum + Math.abs(r.effectiveAmount), 0);
229→
230→      // For current month: actual + pending recurring
231→      // For future months: just projected recurring
232→      const monthActualExpenses = isCurrentMonth ? actualExpenses : 0;
233→      const monthActualIncome = isCurrentMonth ? actualIncome : 0;
234→
235→      totalActualExpensesSum += monthActualExpenses;
236→      totalActualIncomeSum += monthActualIncome;
237→      totalRecurringExpensesSum += recurringExpensesPending;
238→      totalRecurringIncomeSum += recurringIncomePending;
239→
240→      // Total expenses = actual expenses (current month) + pending recurring expenses
241→      // For current month, installments are already included in actual expenses if they exist
242→      // For future months, we add installments separately
243→      let totalExpenses: number;
244→      let totalIncome: number;
245→
246→      if (isCurrentMonth) {
247→        // Actual already includes what was spent (including any installments/recurring already charged)
248→        // Add only pending recurring
249→        totalExpenses = monthActualExpenses + recurringExpensesPending;
250→        totalIncome = monthActualIncome + recurringIncomePending;
251→      } else {
252→        // Future months: installments + all recurring
253→        totalExpenses = installmentsTotal + recurringExpensesPending;
254→        totalIncome = recurringIncomePending;
255→      }
256→
257→      const projectedBalance = totalIncome - totalExpenses;
258→
259→      months.push({
260→        month: normalizedMonth,
261→        year: projYear,
262→        monthLabel,
263→        isCurrentMonth,
264→        actualExpenses: monthActualExpenses,
265→        actualIncome: monthActualIncome,
266→        installmentsTotal,
267→        installmentsCount: monthInstallments.length + monthStandaloneInstallments.length,
268→        installments: installmentItems,
269→        recurringExpenses: recurringExpensesPending,
270→        recurringIncome: recurringIncomePending,
271→        recurringItems,
272→        totalExpenses,
273→        totalIncome,
274→        projectedBalance,
275→        isNegative: projectedBalance < 0,
276→      });
277→    }
278→
279→    const response: ProjectionResponse = {
280→      months,
281→      totals: {
282→        totalInstallments: totalInstallmentsSum,
283→        totalRecurringExpenses: totalRecurringExpensesSum,
284→        totalRecurringIncome: totalRecurringIncomeSum,
285→        netProjectedBalance: totalRecurringIncomeSum - totalInstallmentsSum - totalRecurringExpensesSum,
286→      },
287→    };
288→
289→    return NextResponse.json(response);
290→  } catch (error) {
291→    if (error instanceof Error && error.message === "Unauthorized") {
292→      return unauthorizedResponse();
293→    }
294→    console.error("Error fetching projection:", error);
295→    return NextResponse.json(
296→      { error: "Erro ao buscar projecao financeira" },
297→      { status: 500 }
298→    );
299→  }
300→}
