 46→        currentByMonth[m].income += Math.abs(t.amount);
 47→      } else if (t.type === "EXPENSE") {
 48→        currentByMonth[m].expense += Math.abs(t.amount);
 49→      }
 50→    }
 51→
 52→    // Group previous year by month
 53→    const prevByMonth: Record<number, { income: number; expense: number }> = {};
 54→    for (let m = 1; m <= 12; m++) {
 55→      prevByMonth[m] = { income: 0, expense: 0 };
 56→    }
 57→    for (const t of prevYearTx) {
 58→      const m = new Date(t.date).getMonth() + 1;
 59→      if (t.type === "INCOME") {
 60→        prevByMonth[m].income += Math.abs(t.amount);
 61→      } else if (t.type === "EXPENSE") {
 62→        prevByMonth[m].expense += Math.abs(t.amount);
 63→      }
 64→    }
 65→
 66→    // Build months array
 67→    const months = [];
 68→    let totalIncome = 0;
 69→    let totalExpense = 0;
 70→    let totalPrevIncome = 0;
 71→    let totalPrevExpense = 0;
 72→
 73→    for (let m = 1; m <= 12; m++) {
 74→      const curr = currentByMonth[m];
 75→      const prev = prevByMonth[m];
 76→
 77→      const incomeChange = prev.income > 0
 78→        ? ((curr.income - prev.income) / prev.income) * 100
 79→        : 0;
 80→      const expenseChange = prev.expense > 0
 81→        ? ((curr.expense - prev.expense) / prev.expense) * 100
 82→        : 0;
 83→
 84→      months.push({
 85→        month: m,
 86→        monthLabel: MONTH_LABELS[m - 1],
 87→        income: curr.income,
 88→        expense: curr.expense,
 89→        prevIncome: prev.income,
 90→        prevExpense: prev.expense,
 91→        incomeChange,
 92→        expenseChange,
 93→      });
 94→
 95→      totalIncome += curr.income;
 96→      totalExpense += curr.expense;
 97→      totalPrevIncome += prev.income;
 98→      totalPrevExpense += prev.expense;
 99→    }
100→
101→    return NextResponse.json({
102→      months,
103→      totals: {
104→        income: totalIncome,
105→        expense: totalExpense,
106→        prevIncome: totalPrevIncome,
107→        prevExpense: totalPrevExpense,
108→      },
109→    });
110→  } catch (error) {
111→    if (error instanceof Error && error.message === "Unauthorized") {
112→      return unauthorizedResponse();
113→    }
114→    console.error("Error fetching annual data:", error);
115→    return NextResponse.json(
116→      { error: "Erro ao buscar dados anuais" },
117→      { status: 500 }
118→    );
119→  }
120→}
