          id: 'txn-income',
          description: 'Salary',
          amount: 5000,
          date: new Date(2024, 1, 5),
          type: 'INCOME',
          categoryId: 'cat-salary',
          category: { id: 'cat-salary', name: 'Salario', color: '#10B981' },
          isFixed: false,
          isInstallment: false,
          userId: testUser.id
        },
        // Carryover from January
        {
          id: 'txn-carryover',
          description: 'Saldo Anterior Fatura Janeiro/2024 - Nubank',
          amount: -3000,
          date: new Date(2024, 1, 15),
          type: 'EXPENSE',
          categoryId: null,
          category: null,
          isFixed: false,
          isInstallment: false,
          userId: testUser.id
        }
      ]

      // No bill payments for February
      const billPayments = [
        {
          id: 'bp-1',
          billMonth: 1, // January
          billYear: 2024,
          origin: 'Nubank',
          totalBillAmount: 10000,
          amountPaid: 7000,
          amountCarried: 3000,
          paymentType: 'PARTIAL',
          userId: testUser.id
        }
