      // February:
      // Income: R$ 5,000
      // Expense: R$ 3,000 (carryover)
      // Balance: R$ 2,000
      expect(response.status).toBe(200)
      expect(data.summary.income).toBe(5000)
      expect(data.summary.expense).toBe(3000)
      expect(data.summary.balance).toBe(2000)
    })
